# Define similarity functions
def longest_common_substring(a, b):
    # dynamic programming LCS substring
    m = [[0]*(1+len(b)) for _ in range(1+len(a))]
    longest, x_longest = 0, 0
    for i in range(1, 1+len(a)):
        for j in range(1, 1+len(b)):
            if a[i-1] == b[j-1]:
                m[i][j] = m[i-1][j-1] + 1
                if m[i][j] > longest:
                    longest = m[i][j]
                    x_longest = i
            else:
                m[i][j] = 0
    return a[x_longest-longest: x_longest], longest

def token_f1(a, b):
    # tokens
    ta = a.split()
    tb = b.split()
    ca = Counter(ta)
    cb = Counter(tb)
    common = sum((ca & cb).values())
    if common == 0:
        return 0.0
    prec = common / len(ta)
    rec = common / len(tb)
    return 2*prec*rec / (prec + rec)

